  payload = '{"species": "Banksia", "species_slug": "banksia", "varieties": [{"name": "Banksia integrifolia", "slug": "banksia-integrifolia", "lineage_type": "indigenous", "climate_slug": "humid-subtropical", "sort_order": 0, "origin": "Eastern Australia (Victoria to Central Queensland), collected 1770", "traits": "Highly variable tree/shrub, 2-25m tall (can reach 35m in sheltered locations). Dark green leaves with white undersides create striking contrast in wind. Bark fissured or tessellated.", "flesh_fruit": "", "yield_notes": "", "growing_notes": "", "availability": "Widely available from Queensland and Australian native plant nurseries. One of the most commonly cultivated species."}, {"name": "Banksia dentata", "slug": "banksia-dentata", "lineage_type": "indigenous", "climate_slug": "humid-subtropical", "sort_order": 1, "origin": "Northern Australia (Cooktown to Kimberley), Papua New Guinea, Aru Islands. Collected 1770.", "traits": "Gnarled tree to 7m high. Large green leaves up to 22cm long with dentate (toothed) margins. Only Banksia species not endemic to Australia.", "flesh_fruit": "", "yield_notes": "", "growing_notes": "", "availability": "Available from specialist Australian native nurseries, particularly in Queensland."}, {"name": "Banksia robur", "slug": "banksia-robur", "lineage_type": "indigenous", "climate_slug": "humid-subtropical", "sort_order": 2, "origin": "Eastern Australia (NSW, Queensland), collected 1770 at Botany Bay", "traits": "Large shrub to small tree, 2-5m tall. Highly variable species with diverse color forms even from same seed stock. Grows in sandy soils and swampy sites, prefers constant water access.", "flesh_fruit": "", "yield_notes": "", "growing_notes": "", "availability": "Available from Queensland nurseries including Yuruga Nursery (Mount Windsor seed stock)."}, {"name": "Banksia aemula", "slug": "banksia-aemula", "lineage_type": "indigenous", "climate_slug": "humid-subtropical", "sort_order": 3, "origin": "Subtropical east coast (mid-Queensland to mid-NSW)", "traits": "Sprawly gnarly tree found in beach dunes, coastal areas, and wallum (sandy soils). Brown bark (unlike grey bark of B. serrata). Deep roots access water despite sandy habitat.", "flesh_fruit": "", "yield_notes": "", "growing_notes": "", "availability": "Available from Queensland and NSW coastal region nurseries."}, {"name": "Banksia aquilonia", "slug": "banksia-aquilonia", "lineage_type": "indigenous", "climate_slug": "humid-subtropical", "sort_order": 4, "origin": "North Queensland (Crystal Creek to Ingham region), described 1981", "traits": "Tall shrub/small tree to 8m (occasionally 15m). Narrow glossy green leaves up to 20cm long with distinctive reddish-brown hairs on midrib underside.", "flesh_fruit": "", "yield_notes": "", "growing_notes": "", "availability": "Uncommon in cultivation but becoming more available. Specialist Queensland nurseries."}, {"name": "Banksia plagiocarpa", "slug": "banksia-plagiocarpa", "lineage_type": "indigenous", "climate_slug": "humid-subtropical", "sort_order": 5, "origin": "Hinchinbrook Island and adjacent North Queensland mainland (Mt Bowen, Nina Peak, Bishops Peak). First collected 1867, described 1981.", "traits": "Shrub to 5m high with greyish broken bark. New growth covered in red velvety fur. Narrow lanceolate leaves 8-20cm long.", "flesh_fruit": "", "yield_notes": "", "growing_notes": "", "availability": "Initially rare but rapidly becoming more common in cultivation. Queensland specialist nurseries. Used for cut flower production in coastal NSW and SE Queensland."}, {"name": "Banksia spinulosa", "slug": "banksia-spinulosa", "lineage_type": "indigenous", "climate_slug": "humid-subtropical", "sort_order": 6, "origin": "Eastern Australia (Victoria to Queensland, extending to Cairns). First named 1793.", "traits": "Multi-stemmed shrub 1-3m tall (can reach 5m as single-stemmed tree). Has lignotuber for fire regeneration. Long thin leaves, highly variable flower style colors (black, purple, red, orange, yellow, gold).", "flesh_fruit": "", "yield_notes": "", "growing_notes": "", "availability": ""}, {"name": "Banksia serrata", "slug": "banksia-serrata", "lineage_type": "indigenous", "climate_slug": "humid-subtropical", "sort_order": 7, "origin": "Eastern Australia (southern Victoria through NSW to central Queensland). Collected 1770.", "traits": "Large shrub to tree 10-15m tall. Often gnarly, lumpy, twisted form. Grey tessellated bark. Dark green leaves white beneath. Short and compact in exposed coastal sites, larger in sheltered gardens.", "flesh_fruit": "", "yield_notes": "", "growing_notes": "", "availability": "Widely available from Queensland and Eastern Australian nurseries."}, {"name": "Banksia ericifolia", "slug": "banksia-ericifolia", "lineage_type": "indigenous", "climate_slug": "humid-subtropical", "sort_order": 8, "origin": "Central and Northern NSW east of Great Dividing Range (two separate regions). Collected 1770. Official flower of Sydney.", "traits": "Medium to large shrub 2-6m high (1-2m in exposed coastal areas). Small slender heather-like leaves. Dense growth habit.", "flesh_fruit": "", "yield_notes": "", "growing_notes": "", "availability": ""}, {"name": "Banksia oblongifolia", "slug": "banksia-oblongifolia", "lineage_type": "indigenous", "climate_slug": "humid-subtropical", "sort_order": 9, "origin": "Eastern Australia (mid-Queensland to mid-NSW)", "traits": "Big bushy Banksia found in sandy soils, swampy sites, clay, loam and granite. Grows in forest, bushland and beachfront with access to water.", "flesh_fruit": "", "yield_notes": "", "growing_notes": "", "availability": "Available from Queensland and NSW native plant nurseries."}, {"name": "Banksia paludosa", "slug": "banksia-paludosa", "lineage_type": "indigenous", "climate_slug": "humid-subtropical", "sort_order": 10, "origin": "Eastern Australia (coastal and ranges from Sydney to Victorian border)", "traits": "Small shrub to 2m with whorled leaves. Grows on dry rocky acid soil in open spaces. Perfect size for pots and containers.", "flesh_fruit": "", "yield_notes": "", "growing_notes": "", "availability": "Not often found in gardens, but available from specialist Australian native nurseries."}, {"name": "Banksia marginata", "slug": "banksia-marginata", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "sort_order": 11, "origin": "Southeastern Australia (Eyre Peninsula SA to Baradine NSW, throughout Victoria and Tasmania). One report from Springbrook Mountains near humid subtropical climates.", "traits": "Highly variable: 20cm shrub to 12m tree. Most often 2m shrub. Upper leaf surface dark green, lower surface white-tomentose creating silvery appearance in wind. Most widely distributed Banksia species.", "flesh_fruit": "", "yield_notes": "", "growing_notes": "", "availability": ""}, {"name": "Banksia ''Birthday Candles''", "slug": "banksia-birthday-candles", "lineage_type": "hybrid", "climate_slug": "humid-subtropical", "sort_order": 12, "origin": "Schnapper Point near Ulladulla, NSW (exposed headland). Developed by Bill Molyneux, Austraflora. Plant breeder rights granted 1989.", "traits": "", "flesh_fruit": "", "yield_notes": "", "growing_notes": "", "availability": ""}, {"name": "Banksia ''Cherry Candles''", "slug": "banksia-cherry-candles", "lineage_type": "hybrid", "climate_slug": "humid-subtropical", "sort_order": 13, "origin": "Schnapper Point near Ulladulla, NSW. Released by Austraflora 2004.", "traits": "Compact dwarf 50cm high x 75-90cm wide. Dense, flat growth habit. Flower spikes nearly twice as tall as ''Birthday Candles''.", "flesh_fruit": "", "yield_notes": "", "growing_notes": "", "availability": ""}, {"name": "Banksia ''Honey Pots''", "slug": "banksia-honey-pots", "lineage_type": "hybrid", "climate_slug": "humid-subtropical", "sort_order": 14, "origin": "Selection from Banksia spinulosa", "traits": "Dwarf shrub 1m high x 1-1.5m wide. Dense compact growth. Rugged leaves with bright golden color when young.", "flesh_fruit": "", "yield_notes": "", "growing_notes": "", "availability": "Widely available. Sunshine Coast nurseries, Queensland and Australian-wide retailers."}, {"name": "Banksia ''Coastal Cushion''", "slug": "banksia-coastal-cushion", "lineage_type": "hybrid", "climate_slug": "humid-subtropical", "sort_order": 15, "origin": "Schnapper Point, NSW. Collected by Neil Marriott, propagated by Richard Anderson.", "traits": "Low groundcover 60cm high with twice the spread of ''Birthday Candles'' and ''Cherry Candles''.", "flesh_fruit": "", "yield_notes": "", "growing_notes": "", "availability": "Available from specialist native plant nurseries."}, {"name": "Banksia ''Stumpy Gold''", "slug": "banksia-stumpy-gold", "lineage_type": "hybrid", "climate_slug": "humid-subtropical", "sort_order": 16, "origin": "Selection from Hairpin Banksia", "traits": "Low growing dwarf form with mounded growth habit", "flesh_fruit": "", "yield_notes": "", "growing_notes": "", "availability": "Available from Australian native plant nurseries."}, {"name": "Banksia ''Giant Candles''", "slug": "banksia-giant-candles", "lineage_type": "hybrid", "climate_slug": "humid-subtropical", "sort_order": 17, "origin": "Originated at humid subtropical climates garden (spontaneous hybrid). Propagated and registered by Russell Costin, Limpinwood Nursery, 1970s.", "traits": "Large shrub to 5m tall x 5m wide. Can be pruned hard and resprouts from lignotuber. Grows 800mm/year in ideal conditions.", "flesh_fruit": "", "yield_notes": "", "growing_notes": "", "availability": "Widely available. Popular in Queensland and Eastern Australia. May need pruning for space-limited gardens."}, {"name": "Banksia ''Little Eric''", "slug": "banksia-little-eric", "lineage_type": "hybrid", "climate_slug": "humid-subtropical", "sort_order": 18, "origin": "Arose as chance garden seedling. Propagated by Richard Anderson, Merricks Nursery (Mornington Peninsula, VIC).", "traits": "Dwarf compact form 1.5-2m high x 1-1.5m wide. Dense habit. Excellent for small gardens.", "flesh_fruit": "", "yield_notes": "", "growing_notes": "", "availability": ""}, {"name": "Banksia ''Bulli Baby''", "slug": "banksia-bulli-baby", "lineage_type": "hybrid", "climate_slug": "humid-subtropical", "sort_order": 19, "origin": "NSW coastal selection", "traits": "Compact dwarf 1.5m high x 1.2m wide. Extremely floriferous - 50-60 flower heads per season on mature plants.", "flesh_fruit": "", "yield_notes": "", "growing_notes": "", "availability": ""}, {"name": "Banksia ''Bronzed Aussie''", "slug": "banksia-bronzed-aussie", "lineage_type": "hybrid", "climate_slug": "humid-subtropical", "sort_order": 20, "origin": "Unknown origin. Propagated by Rod Parsons, Carawah Nursery. Seed given to Rod''s father by SGAP member many years ago, propagated vegetatively since.", "traits": "Medium shrub to 2m high. Unique bud clustering at base of main flower.", "flesh_fruit": "", "yield_notes": "", "growing_notes": "", "availability": "Available from Carawah Nursery and select retailers."}, {"name": "Banksia ''Roller Coaster''", "slug": "banksia-roller-coaster", "lineage_type": "hybrid", "climate_slug": "humid-subtropical", "sort_order": 21, "origin": "Coastal NSW selection. Also marketed as ''Austraflora Roller Coaster''.", "traits": "Vigorous prostrate groundcover spreading 4-5m wide but remaining only 50cm high. Excellent coastal tolerance.", "flesh_fruit": "", "yield_notes": "", "growing_notes": "", "availability": "Registered cultivar, available from Australian native plant nurseries."}, {"name": "Banksia ''Pygmy Possum''", "slug": "banksia-pygmy-possum", "lineage_type": "hybrid", "climate_slug": "humid-subtropical", "sort_order": 22, "origin": "Dwarf coastal form of Saw Banksia", "traits": "Prostrate groundcover with spreading growth. Low-growing form of normally 5-6m upright species.", "flesh_fruit": "", "yield_notes": "", "growing_notes": "", "availability": "Available from native plant specialists."}, {"name": "Banksia ''Mini Marg''", "slug": "banksia-mini-marg", "lineage_type": "hybrid", "climate_slug": "humid-subtropical", "sort_order": 23, "origin": "Selected compact form of Silver Banksia", "traits": "Compact shrub form, much smaller than typical 2-12m species range", "flesh_fruit": "", "yield_notes": "", "growing_notes": "", "availability": "Available from southern Australian nurseries."}, {"name": "Banksia ''Yellow Wing''", "slug": "banksia-yellow-wing", "lineage_type": "hybrid", "climate_slug": "humid-subtropical", "sort_order": 24, "origin": "Deliberately hybridized by Austraflora", "traits": "Similar size to ''Coastal Cushion''. Named for frequent visits by New Holland honeyeaters.", "flesh_fruit": "", "yield_notes": "", "growing_notes": "", "availability": "Available from Austraflora and select retailers."}, {"name": "Banksia coccinea (Scarlet Banksia) ⚠️ NOT SUITABLE", "slug": "banksia-coccinea-scarlet-banksia-not-suitable", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "sort_order": 25, "origin": "SW Western Australia (Denmark to Stirling Range)", "traits": "", "flesh_fruit": "", "yield_notes": "", "growing_notes": "", "availability": ""}, {"name": "Banksia baxteri (Bird''s Nest Banksia) ⚠️ NOT SUITABLE", "slug": "banksia-baxteri-bird-s-nest-banksia-not-suitable", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "sort_order": 26, "origin": "SW Western Australia (Albany to Stirling Range)", "traits": "", "flesh_fruit": "", "yield_notes": "", "growing_notes": "", "availability": ""}, {"name": "Banksia prionotes (Acorn Banksia) ⚠️ NOT SUITABLE", "slug": "banksia-prionotes-acorn-banksia-not-suitable", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "sort_order": 27, "origin": "SW Western Australia", "traits": "", "flesh_fruit": "", "yield_notes": "", "growing_notes": "", "availability": ""}], "variety_count": 28}'::jsonb,
  variety_count = 28
